+/// Check if any component of a path starts with `.` (hidden file/directory).
+fn has_hidden_component(path: &Path) -> bool {
+    path.components().any(|c| {
+        c.as_os_str()
+            .to_str()
+            .is_some_and(|s| s.starts_with('.') && s != "." && s != "..")
+    })
+}
